const getHighlightedNodes = (hoveredId: string | null, graph: ExpertiseGraph | null) => {
                        if (!hoveredId || !graph) return new Set<string>();
                        const highlighted = new Set<string>([hoveredId]);

                        const queue: string[] = [hoveredId];
                        const visited = new Set<string>([hoveredId]);

                        while (queue.length > 0) {
                                                const curr = queue.shift()!;
                                                for (const edge of graph.edges) {
                                                                        if (
                                                                                                edge.source ===
                                                                                                                        curr &&
                                                                                                !visited.has(
                                                                                                                        edge.target
                                                                                                )
                                                                        ) {
                                                                                                visited.add(
                                                                                                                        edge.target
                                                                                                );
                                                                                                highlighted.add(
                                                                                                                        edge.target
                                                                                                );
                                                                                                queue.push(
                                                                                                                        edge.target
                                                                                                );
                                                                        }
                                                                        if (
                                                                                                edge.target ===
                                                                                                                        curr &&
                                                                                                !visited.has(
                                                                                                                        edge.source
                                                                                                )
                                                                        ) {
                                                                                                visited.add(
                                                                                                                        edge.source
                                                                                                );
                                                                                                highlighted.add(
                                                                                                                        edge.source
                                                                                                );
                                                                                                queue.push(
                                                                                                                        edge.source
                                                                                                );
                                                                        }
                                                }
                        }
                        return highlighted;
};

